{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=60.5,y=69,band={65,67},quest="Picking Up Some Power Converters",text="Picking Up Some Power Converters",detail="Toshley has asked you to take the Protovoltaic Magneto Collector and gather up 5 Electromentals. Return to him at Toshley's Station in the Blade's Edge Mountains after you have done so.",races=1101},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=60.5,y=69,band={65,67},quest="Ride the Lightning",text="Ride the Lightning",detail="Toshley wants you to use the Repolarized Magneto Sphere to absorb 25 lightning strikes from the Scalewing Serpents. As well, collect 5 Scalewing Lightning Glands. Then, deliver them back to him at Toshley's Station in the Blade's Edge Mountains.",races=1101},
