{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=52.4,y=57.9,band={65,66},quest="Dust from the Drakes",text="Dust from the Drakes",detail="Gor'drek wants you to gather 4 Dusts of the Fey Drake. After doing so, return to him at Thunderlord Stronghold in the Blade's Edge Mountains.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=51.9,y=57.8,band={65,66},quest="Felling an Ancient Tree",text="Felling an Ancient Tree",detail="Acquire Stronglimb Deeproot's Trunk and deliver it to Tor'chunk Twoclaws at Thunderlord Stronghold in the Blade's Edge Mountains.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=52.4,y=57.9,band={65,66},quest="Protecting Our Own",text="Protecting Our Own",detail="Use Gor'drek's Ointment on 5 of the Thunderlord Dire Wolves to strengthen them and the defense of the Jagged Ridge. Then return to Gor'drek at Thunderlord Stronghold in the Blade's Edge Mountains.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=51.9,y=58.4,band={65,66},quest="The Bladespire Threat",text="The Bladespire Threat",detail="Tor'chunk Twoclaws has tasked you with the destruction of any 30 Bladespire Ogres and 10 Bladespire Raptors at Bladespire Hold and the Bladespire Grounds. Return to him at Thunderlord Stronghold in the Blade's Edge Mountains once your task is completed.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=51.9,y=58.4,band={65,66},quest="The Bloodmaul Ogres",text="The Bloodmaul Ogres",detail="You have been asked by Tor'chunk Twoclaws to kill any 30 Bloodmaul Ogres at Bloodmaul Outpost. Return to him at Thunderlord Stronghold in the Blade's Edge Mountains once you have done so.",races=690},
