{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=51.8,y=58.4,band={65,67},quest="Baron Sablemane",text="Baron Sablemane",detail="Speak with Baron Sablemane at the Circle of Blood in the Blade's Edge Mountains.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=51.9,y=58.4,band={65,67},quest="Crush the Bloodmaul Camp",text="Crush the Bloodmaul Camp",detail="Tor'chunk Twoclaws has asked you to slay 10 Bloodmaul Maulers and 5 Bloodmaul Warlocks. Afterward, return to him at Thunderlord Stronghold in the Blade's Edge Mountains.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=51.8,y=58.4,band={65,67},quest="On Spirit's Wings",text="On Spirit's Wings",detail="Find a Bloodmaul Taskmaster and a Bloodmaul Soothsayer engaged in conversation, then use Rexxar's Whistle to summon Spirit to spy on them. When this is complete, return to Rexxar at Thunderlord Village in the Blade's Edge Mountains.",races=690},
