{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=52,y=54.4,band={67,67},quest="The Apprentice's Request",text="The Apprentice's Request",detail="Speak with Dama Wildmane at Shadowmoon Village.",races=690},
