{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=52.8,y=59,band={65,67},quest="The Spirits Have Voices",text="The Spirits Have Voices",detail="Garm Wolfbrother has told you where the Mok'Nathal, Rexxar's people, live. Speak of this to Rexxar at Thunderlord Stronghold in the Blade's Edge Mountains.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=52.8,y=59,band={65,67},quest="The Thunderspike",text="The Thunderspike",detail="Rokgah Bloodgrip has tasked you with the retrieval of the Thunderspike. Return it to her at Thunderlord Stronghold in the Blade's Edge Mountains.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=51.8,y=58.4,band={65,68},quest="Gorgrom the Dragon-Eater",text="Gorgrom the Dragon-Eater",detail="Go to Boulder'mok and collect 3 Grisly Totems from the Boulder'mok ogres. Use Sablemane's Trap at Gorgrom's Altar to set the trap and summon and kill Gorgrom the Dragon-Eater.",races=690},
