{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=51.8,y=58.4,band={65,70},quest="Showdown",text="Showdown",detail="Use Rexxar's Battle Horn at the Altar of Goc, then kill Goc. Return to Rexxar at Thunderlord Village in the Blade's Edge Mountains when this is done.",races=690},
