{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=37.4,y=64.7,band={65,66},quest="Strange Brew",text="Strange Brew",detail="Borgrim Stouthammer wants you to procure 11 Bloodmaul Brutebane Brew for him. Once you've done that, return it to him at Sylvanaar in the Blade's Edge Mountains.",races=1101},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=36.2,y=66.2,band={65,66},quest="The Bladespire Ogres",text="The Bladespire Ogres",detail="You have been asked by Commander Skyshadow to kill any 30 Bladespire Ogres in Bladespire Hold and the Bladespire Grounds. Return to him at Sylvanaar in the Blade's Edge Mountains once you have done so.",races=1101},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=36.2,y=66.2,band={65,66},quest="The Bloodmaul Ogres",text="The Bloodmaul Ogres",detail="Commander Skyshadow has tasked you with the destruction of any 30 Bloodmaul Ogres at Bloodmaul Outpost. Return to him at Sylvanaar in the Blade's Edge Mountains once your gruesome task is completed.",races=1101},
