{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=36.2,y=67.1,band={65,66},quest="The Encroaching Wilderness",text="The Encroaching Wilderness",detail="Rina Moonspring wishes you to slay 12 Grovestalker Lynxes with all due haste and then return to her at Sylvanaar in the Blade's Edge Mountains.",races=1101},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=36.2,y=66.2,band={65,67},quest="Where Did Those Darn Gnomes Go?",text="Where Did Those Darn Gnomes Go?",detail="Commander Skyshadow has asked you to look in the southern area of the Jagged Ridge of the Blade's Edge Mountains for a clue as to the whereabouts of Toshley and the other gnomes.",races=1101},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=45,y=72.3,band={65,66},quest="A Curse Upon Both of Your Clans!",text="A Curse Upon Both of Your Clans!",detail="Use the Wicked Strong Fetish to curse 5 buildings or towers in Bladespire Hold and 2 in Bloodmaul Outpost. Return to T'chali the Witch Doctor at Bloodmaul Ravine in the Blade's Edge Mountains after you have done so.",races=690},
