{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=45,y=72.3,band={65,67},quest="Grimnok and Korgaah, I Am For You!",text="Grimnok and Korgaah, I Am For You!",detail="T'chali the Witch Doctor has asked you to kill his chief tormentors, Grimnok Battleborn and Korgaah. After you have done so, return to him at Bloodmaul Ravine in the Blade's Edge Mountains.",races=690},
