{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=32.2,y=91.1,band={65,65},quest="Killing the Crawlers",text="Killing the Crawlers",detail="Sentinel Moonwhisper at the tunnel between Zangarmarsh and Blade's Edge Mountains wants you to kill 6 Cavern Crawlers and report to Commander Skyshadow in Sylvanaar.",races=1101},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=53,y=96.2,band={65,65},quest="Killing the Crawlers",text="Killing the Crawlers",detail="Grunt Grahk at the tunnel between Zangarmarsh and Blade's Edge Mountains wants you to kill 6 Cavern Crawlers and report to Tor'chunk Two-claws in Thunderlord Stronghold.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=75.1,y=62.1,band={64,64},quest="Ruuan Weald",text="Ruuan Weald",detail="Speak with Timeon at Evergrove, which is in the Ruuan Weald in the Blade's Edge Mountains.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=75.8,y=61.5,band={64,65},quest="The Softest Wings",text="The Softest Wings",detail="Silmara at Mok'Nathal Village wants you to collect 12 Iridescent Wings.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=75.9,y=61.4,band={64,66},quest="Silkwing Cocoons",text="Silkwing Cocoons",detail="Taerek at Mok'Nathal Village wants you to collect 8 Silkwing Cocoons from Silkwing Larva.",races=690},
