{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=74.9,y=60.5,band={65,67},quest="The Totems of My Enemy",text="The Totems of My Enemy",detail="Collect 5 Bladespire Totems for Spiritcaller Dohgar at Mok'Nathal Village in the Blade's Edge Mountains.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=75.3,y=60.9,band={65,67},quest="Understanding the Mok'Nathal",text="Understanding the Mok'Nathal",detail="To begin your understanding of the Mok'Nathal, slay Vekh, leader of the Vekh'nir arakkoa. Then, return to Leoroxx at Mok'Nathal Village in the Blade's Edge Mountains.",races=690},
