{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=75.3,y=60.9,band={65,68},quest="Since Time Forgotten...",text="Since Time Forgotten...",detail="In order to prove yourself to the Mok'Nathal, Leoroxx has ordered you to slay Gnosh Brognat, leader of the ogres at the Bladespire Outpost. Return to Leoroxx at Mok'Nathal Village in the Blade's Edge Mountains after you have done so, or do not return at all.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=75.3,y=60.9,band={65,68},quest="Slay the Brood Mother",text="Slay the Brood Mother",detail="Leoroxx has challenged you to slay Dreadwing. Return to him at Mok'Nathal Village once you have managed to kill her.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=75.3,y=60.9,band={65,68},quest="There Can Be Only One Response",text="There Can Be Only One Response",detail="Leoroxx has beseeched you to retrieve the Collection of Souls and return them to Spiritcaller Dohgar at Mok'Nathal Village in the Blade's Edge Mountains.",races=690},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=62.2,y=39.1,band={66,66},quest="Creating the Pendant",text="Creating the Pendant",detail="Find 6 Ruuan'ok Claws and use them at the Ruaan'ok Oracle Circle to summon a Harbinger of the Raven. Kill it and return its Harbinger's Pendant to Timeon at Ruuan Weald."},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=62,y=39.5,band={65,67},quest="...and a Time for Action",text="...and a Time for Action",detail="Venture out into the Ruuan Weald and slay 10 Wyrmcult Hewers, then return to Tree Warden Chawn at Evergrove in the Blade's Edge Mountains."},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=62,y=38,band={65,67},quest="A Date with Dorgok",text="A Date with Dorgok",detail="Commander Haephus Stonewall has asked you to kill Dorgok at Bloodmaul Camp. Return to him at Evergrove in the Blade's Edge Mountains after you have done the deed.",races=1101},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=62,y=39.5,band={65,67},quest="A Time for Negotiation...",text="A Time for Negotiation...",detail="Tree Warden Chawn has asked you to negotiate with Overseer Nuaar. Return to the tree warden at Evergrove in the Blade's Edge Mountains afterward."},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=62,y=38,band={65,67},quest="Baron Sablemane Has Requested Your Presence",text="Baron Sablemane Has Requested Your Presence",detail="You have received an invitation to speak again with Baron Sablemane on some matter of import. Go to him at the Circle of Blood in the Blade's Edge Mountains.",races=1101},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=62,y=37.9,band={65,67},quest="Crush the Bloodmaul Camp!",text="Crush the Bloodmaul Camp!",detail="Lieutenant Fairweather has tasked you with slaying 10 Bloodmaul Maulers and 5 Bloodmaul Warlocks. Afterward, return to her at Evergrove in the Blade's Edge Mountains.",races=1101},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=62.6,y=38.3,band={65,67},quest="Culling the Wild",text="Culling the Wild",detail="Kill 4 Felsworn Scalewing, 4 Felsworn Daggermaw, and 2 Fel Corrupters."},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=61.3,y=38.5,band={65,67},quest="From the Ashes",text="From the Ashes",detail="Mosswood the Ancient wants you to journey to Skald and plant Ironroot Seeds in three different mounds of Fertile Volcanic Soil and then return to him in Ruuan Weald."},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=61.3,y=38.5,band={65,67},quest="Little Embers",text="Little Embers",detail="Mosswood the Ancient wants you to kill 8 Scorch Imps and then return to him in Ruuan Weald."},
{kind="quest",zone="Blade's Edge Mountains",mapID=1949,x=62,y=38,band={65,67},quest="Pay the Baron a Visit",text="Pay the Baron a Visit",detail="Speak with Baron Sablemane about fashioning a trap. He is located at the Circle of Blood in the Blade's Edge Mountains.",races=1101},
