{kind="quest",zone="Netherstorm",mapID=1953,x=59.5,y=32.4,band={70,70},quest="Ethereum Secrets",text="Ethereum Secrets",detail="Commander Ameer at the Protectorate Watch Post in Netherstorm wants you to bring him an Ethereum Prisoner I.D. Tag."},
{kind="quest",zone="Netherstorm",mapID=1953,x=60.1,y=31.7,band={68,70},quest="On Nethery Wings",text="On Nethery Wings",detail="Professor Dabiri at the Protectorate Watch Post in Netherstorm wants you to use your Phase Disruptor when you get in range of the Void Conduit that rests atop Ultris. Drop as many charges of the Phase Disruptor as you can to ensure total annihilation. The Phase Disruptor charges will automatically home in on the Void Conduit so long as you are close enough to use it."},
{kind="quest",zone="Netherstorm",mapID=1953,x=60.1,y=31.7,band={68,70},quest="Recipe for Destruction",text="Recipe for Destruction",detail="Professor Dabiri at the Protectorate Watch Post in Netherstorm wants you to recover 8 Fragments of Dimensius."},
{kind="quest",zone="Netherstorm",mapID=1953,x=59.5,y=32.4,band={68,70},quest="The Ethereum",text="The Ethereum",detail="Commander Ameer wants you to kill 5 Ethereum Assassins, 5 Ethereum Shocktroopers, 2 Ethereum Researchers and Captain Zovax then activate Ethereum Transponder Zeta."},
{kind="quest",zone="Netherstorm",mapID=1953,x=58.4,y=31.3,band={67,70},quest="Triangulation Point Two",text="Triangulation Point Two",detail="Use the Triangulation Device to point your way toward the second triangulation point. Once you have found it, report the location to Wind Trader Tuluman at Tuluman's Landing, just on the other side of the bridge from the Manaforge Ara island in the Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1953,x=71.2,y=35.1,band={68,70},quest="A Promising Start",text="A Promising Start",detail="Gather 15 Nether Dragonkin Eggs, then return to Tyri and Jorad on the Celestial Ridge."},
{kind="quest",zone="Netherstorm",mapID=1953,x=70.9,y=38.8,band={68,70},quest="Formal Introductions",text="Formal Introductions",detail="Find Tyri at the north end of the Celestial Ridge and speak with her."},
{kind="quest",zone="Netherstorm",mapID=1953,x=71.2,y=35.1,band={68,70},quest="Securing the Celestial Ridge",text="Securing the Celestial Ridge",detail="Use the Challenge of the Blue Flight to provoke Veraku on the southern edge of the Celestial Ridge. Defeat him and return to Tyri and Jorad on the Celestial Ridge."},
{kind="quest",zone="Netherstorm",mapID=1953,x=71.2,y=35.1,band={68,70},quest="Troublesome Distractions",text="Troublesome Distractions",detail="Speak with Wind Trader Marid and lure him away from his trading post. Deal with him and then return to Tyri and Jorad on the Celestial Ridge."},
{kind="quest",zone="Netherstorm",mapID=1953,x=42.3,y=32.6,band={67,69},quest="Creatures of the Eco-Domes",text="Creatures of the Eco-Domes",detail="Tag 12 Talbuks for Aurine Moonblaze at the Stormspire. You may tag either Talbuk Sires or Talbuk Does using the Talbuk Tagger."},
{kind="quest",zone="Netherstorm",mapID=1953,x=43.5,y=35.2,band={67,69},quest="Diagnosis: Critical",text="Diagnosis: Critical",detail="Use the Diagnostic Device while standing near the Eco-Dome Sutheron Generator and bring the Diagnostic Results back to Ghabar at the Stormspire."},
{kind="quest",zone="Netherstorm",mapID=1953,x=44.7,y=34.9,band={67,69},quest="Fel Reavers, No Thanks!",text="Fel Reavers, No Thanks!",detail="Obtain 5 Condensed Nether Gas from Gan'arg Mekgineers at Forge Base: Oblivion, northwest of the Stormspire, and load them into a nearby Inactive Fel Reaver. Return to Nether-Stalker Nauthis after you've completed this task."},
{kind="quest",zone="Netherstorm",mapID=1953,x=42.3,y=32.6,band={67,69},quest="Flora of the Eco-Domes",text="Flora of the Eco-Domes",detail="Use the Energy Field Modulator on Farahlon Lashers. Observe the results and report back to Aurine Moonblaze at the Stormspire when you have conducted 10 tests."},
{kind="quest",zone="Netherstorm",mapID=1953,x=44.1,y=36.1,band={68,69},quest="Hitting the Motherlode",text="Hitting the Motherlode",detail="Zuben Elgenubi at the Stormspire wants you to obtain a Farahlite Core."},
{kind="quest",zone="Netherstorm",mapID=1953,x=44.7,y=36.8,band={67,69},quest="Retrieving the Goods",text="Retrieving the Goods",detail="Audi the Needle at the Stormspire wants you to bring her 10 Dome Generator Segments."},
{kind="quest",zone="Netherstorm",mapID=1953,x=44.7,y=34.9,band={67,69},quest="Teleport This!",text="Teleport This!",detail="Nether-Stalker Nauthis wants you to use the Mental Interference Rod on the Mo'arg at Forge Base: Gehenna and use their Detonate Teleporter ability on the three teleporters in the forge camp."},
{kind="quest",zone="Netherstorm",mapID=1953,x=43.5,y=35.2,band={67,69},quest="Testing the Prototype",text="Testing the Prototype",detail="Bring the Repair Apparatus to Tashar at Eco-Dome Farfield."},
{kind="quest",zone="Netherstorm",mapID=1953,x=44.7,y=34.9,band={67,69},quest="The Best Defense",text="The Best Defense",detail="Nether-Stalker Nauthis wants you to slay 12 Wrathbringers at Forge Base: Gehenna, north of the Stormspire."},
{kind="quest",zone="Netherstorm",mapID=1953,x=45.9,y=36,band={67,69},quest="Triangulation Point One",text="Triangulation Point One",detail="Use the Triangulation Device to point your way toward the first triangulation point. Once you have found it, report the location to Dealer Hazzin at the Protectorate Watchpost on the Manaforge Ultris island in the Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1953,x=42.3,y=32.6,band={67,69},quest="When Nature Goes Too Far",text="When Nature Goes Too Far",detail="Aurine Moonblaze at the Stormspire wants you to bring her a Hulking Hydra Heart."},
{kind="quest",zone="Netherstorm",mapID=1953,x=44.1,y=36.1,band={68,70},quest="In Search of Farahlite",text="In Search of Farahlite",detail="Gather 4 pieces of Raw Farahlite and return to Zuben Elgenubi at the Stormspire."},
{kind="quest",zone="Netherstorm",mapID=1953,x=45.8,y=36.3,band={70,70},quest="Seek Out Ameer",text="Seek Out Ameer",detail="Seek out Commander Ameer at the Protectorate Watch Post."},
{kind="quest",zone="Netherstorm",mapID=1953,x=44.7,y=34.9,band={68,70},quest="Surveying the Ruins",text="Surveying the Ruins",detail="Place the three Surveying Markers and then return to Zephyrion at the Stormspire in the Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1953,x=44.7,y=34.9,band={68,70},quest="The Minions of Culuthas",text="The Minions of Culuthas",detail="Slay 10 Hounds of Culuthas and 5 Eyes of Culuthas. Then return to Nether-Stalker Nauthis at the Stormspire in the Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1953,x=34.8,y=38.3,band={67,70},quest="A Dark Pact",text="A Dark Pact",detail="Kaylaan at Tuluman's Landing in Netherstorm wants you to slay 6 Gan'arg Warp-Tinkers, 3 Daughters of Destiny and 3 Mo'arg Warp-Masters."},
{kind="quest",zone="Netherstorm",mapID=1953,x=34.8,y=38.3,band={67,70},quest="Aldor No More",text="Aldor No More",detail="Report back to Exarch Orelis at Area 52."},
{kind="quest",zone="Netherstorm",mapID=1953,x=34.6,y=38,band={68,70},quest="Dealing with the Foreman",text="Dealing with the Foreman",detail="Deal with Foreman Sundown inside the Trelleum Mine, which is underneath Manaforge Ara in the Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1953,x=34.6,y=38,band={67,70},quest="Full Triangle",text="Full Triangle",detail="Recover the Ata'mal Crystal and deliver it to the Image of Nexus-Prince Haramad at the Stormspire in the Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1953,x=34.5,y=37.8,band={68,70},quest="Neutralizing the Nethermancers",text="Neutralizing the Nethermancers",detail="Kill 15 Sunfury Nethermancers and return to Nether-Stalker Oazul at Tuluman's Landing in the Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1953,x=26.2,y=41.6,band={67,70},quest="Damning Evidence",text="Damning Evidence",detail="Obtain 8 Orders from Kael'thas from demons at Manaforge Ara and bring them to Spymaster Thalodien in Area 52."},
{kind="quest",zone="Netherstorm",mapID=1953,x=26.4,y=42.3,band={68,70},quest="Dealing with the Overmaster",text="Dealing with the Overmaster",detail="Slay Overmaster Grindgarr. Then return to Wind Trader Tuluman at Tuluman's Landing in the Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1953,x=35.9,y=28.9,band={67,70},quest="Nether Gas In a Fel Fire Engine",text="Nether Gas In a Fel Fire Engine"},
{kind="quest",zone="Netherstorm",mapID=1953,x=44.7,y=14.6,band={67,69},quest="All Clear!",text="All Clear!",detail="Tashar, stationed at Eco-Dome Farfield, wants you to kill 12 Scythetooth Raptors."},
{kind="quest",zone="Netherstorm",mapID=1953,x=44.7,y=14.6,band={67,69},quest="Success!",text="Success!",detail="Return to the Stormspire and speak with Ghabar."},
{kind="quest",zone="Netherstorm",mapID=1953,band={2,68},quest="BETA Netherologist Coppernickels",text="BETA Netherologist Coppernickels",detail="Speak with Netherologist Coppernickels at the bridge leading into the Netherstorm from Blade's Edge."},
{kind="quest",zone="Netherstorm",mapID=1953,band={2,68},quest="BETA The Custodian of Kirin'Var",text="BETA The Custodian of Kirin'Var",detail="Speak with Custodian Dierworth in Kirin'Var Village."},
{kind="quest",zone="Netherstorm",mapID=1953,band={67,68},quest="Battle-Mage Dathric",text="Battle-Mage Dathric",detail="Locate Battle-Mage Dathric's quarters in Wizard's Row and return the blade to his weapon rack. Then, speak with Custodian Dieworth at Kirin'Var Village."},
