{kind="quest",zone="Netherstorm",mapID=1953,band={67,69},quest="Summoner Kanthin's Prize",text="Summoner Kanthin's Prize",detail="Defeat Summoner Kanthin at Manaforge Duro, on the island to the north of Sunfury Hold, and reclaim the Stone of Glacius from him. When you have obtained the stone, use Archmage Vargoth's Staff to contact the archmage."},
