{kind="quest",zone="Netherstorm",mapID=1953,band={67,69},quest="Cohlien Frostweaver",text="Cohlien Frostweaver",detail="Locate Cohlien Frostweaver's quarters in Wizard Row and return the hat to his Footlocker. Then, speak with Custodian Dieworth at Kirin'Var Village."},
{kind="quest",zone="Netherstorm",mapID=1953,band={67,69},quest="BETA R.T.F.R.C.M.",text="BETA R.T.F.R.C.M.",detail="Take the Fel Reaver Construction Manual to Mama Wheeler at the Midrealm Post inside Eco-Dome Midrealm in the Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1953,band={67,69},quest="Krasus's Compendium",text="Krasus's Compendium",detail="Reclaim Krasus's Compendium - Chapter 1, Krasus's Compendium - Chapter 2, and Krasus's Compendium - Chapter 3 from Kirin'Var Village's Town Square. Use Archmage Vargoth's Staff to contact the archmage once you have the chapters."},
{kind="quest",zone="Netherstorm",mapID=1953,band={2,69},quest="BETA A Message for the Archmage",text="BETA A Message for the Archmage",detail="Speak to Archmage Vargoth at the top of the Violet Tower."},
{kind="quest",zone="Netherstorm",mapID=1953,band={68,70},quest="BETA Against the Legion",text="BETA Against the Legion",detail="Exarch Orelis at Area 52 wants you to go to Forge Base: Oblivion and Forge Base: Gehenna and slay 12 Gan'arg Forgehands, 6 Mo'arg Forgelords and 6 Wrathbringers.",races=1101},
{kind="quest",zone="Netherstorm",mapID=1953,band={68,70},quest="Getting Down to Business",text="Getting Down to Business",detail="Gather 8 Nether Dragon Essence, then return to the Ethereal Teleport Pad area. Nether Dragon Essence may be obtained from Nether Drakes or Nether Dragons."},
{kind="quest",zone="Netherstorm",mapID=1430,x=47.3,y=75.2,band={70,70},quest="A Colleague's Aid",text="A Colleague's Aid",detail="Take the Charred Bone Fragment to Kalynna Lathred at Area 52 in Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1953,band={68,70},quest="The Horrors of Pollution",text="The Horrors of Pollution",detail="Take the Vial of Void Horror Ooze to Researcher Navuud at the Protectorate Watch Post in Netherstorm."},
{kind="quest",zone="Netherstorm",mapID=1955,x=42.8,y=91.7,band={67,70},quest="Turning Point",text="Turning Point",detail="Use Socrethar's Teleportation's Stone at Invasion Point: Overlord, north of Forge Base: Oblivion to transport your party to Socrethar's Landing. Once there, use Voren'thal's Presence to defeat Socrethar."},
{kind="quest",zone="Netherstorm",mapID=1955,x=62.8,y=36,band={70,70},quest="Sunfury Attack Plans",text="Sunfury Attack Plans",detail="Lord Torvos in Shattrath wants you to capture the Sunfury Attack Plans."},
