{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=40.8,y=22.3,band={67,70},quest="News of Victory",text="News of Victory",detail="Return to Wildhammer Stronghold and speak with Kurdran Wildhammer.",races=1101},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=44.6,y=23.7,band={68,70},quest="The Cipher of Damnation - Grom'tor's Charge",text="The Cipher of Damnation - Grom'tor's Charge",detail="Grom'tor, Son of Oronok at Coilskar Point in Shadowmoon Valley wants you to recover the First Fragment of the Cipher of Damnation."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=44.6,y=23.7,band={68,70},quest="The Cipher of Damnation - The First Fragment Recovered",text="The Cipher of Damnation - The First Fragment Recovered",detail="Take Grom'tor's Lockbox to Oronok Torn-heart at Oronok's Farm in Shadowmoon Valley."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=54,y=23.5,band={68,70},quest="A Lesson Learned",text="A Lesson Learned",detail="Oronok Torn-heart at Oronok's Farm in Shadowmoon Valley wants you to destroy 10 Ravenous Flayer Eggs on the Shattered Plains."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=54,y=23.5,band={68,70},quest="Ar'tor, Son of Oronok",text="Ar'tor, Son of Oronok",detail="Find Ar'tor, Son of Oronok at Illidari Point in Shadowmoon Valley."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=54,y=23.5,band={68,70},quest="Borak, Son of Oronok",text="Borak, Son of Oronok",detail="Find Borak, Son of Oronok near Eclipse Point in Shadowmoon Valley."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=51.9,y=18.2,band={67,70},quest="Escape from Coilskar Cistern",text="Escape from Coilskar Cistern",detail="Escort Earthmender Wilda out of Coilskar Cistern and then seek out Earthmender Torlok at the Altar of Damnation, found at the western outskirts of the Hand of Gul'dan."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=54,y=23.5,band={68,70},quest="Grom'tor, Son of Oronok",text="Grom'tor, Son of Oronok",detail="Find Grom'tor, Son of Oronok at Coilskar Point in Shadowmoon Valley."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=54,y=23.5,band={68,70},quest="I Was A Lot Of Things...",text="I Was A Lot Of Things...",detail="Oronok Torn-heart at Oronok's Farm in Shadowmoon Valley wants you to recover 10 Shadowmoon Tubers from the Shattered Plains."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=54,y=23.5,band={68,70},quest="The Cipher of Damnation",text="The Cipher of Damnation",detail="Use the Cipher of Damnation at the Altar of Damnation to summon Cyrukh the Firelord."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=54,y=23.5,band={68,70},quest="The Cipher of Damnation - Truth and History",text="The Cipher of Damnation - Truth and History",detail="Oronok Torn-heart at Oronok's Farm in Shadowmoon Valley wants you to listen to his story. Speak to Oronok to begin hearing his story."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=61.2,y=29.2,band={68,70},quest="A Necessary Distraction",text="A Necessary Distraction",detail="Exarch Onaala wants you to return to the Ruins of Karabor and find a way to unleash Azaloth on his captors."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=62.6,y=28.4,band={70,70},quest="Commander Arcus",text="Commander Arcus",detail="Give the Dragonmaw Flare to Commander Arcus at the Altar of Sha'tar in Shadowmoon Valley."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=61.2,y=29.2,band={68,70},quest="Karabor Training Grounds",text="Karabor Training Grounds",detail="Exarch Onaala at the Altar of Sha'tar wants you to obtain 8 Sunfury Glaives from Demon Hunter Supplicants and Demon Hunter Initiates at the Ruins of Karabor, southeast of the Altar of Sha'tar."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=62.6,y=28.4,band={68,70},quest="Oronu the Elder",text="Oronu the Elder",detail="Anchorite Ceyla at the Altar of Sha'tar wants you to obtain the Orders from Akama from Oronu the Elder at the Ruins of Baa'ri."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=61.2,y=29.1,band={68,70},quest="Reclaiming Holy Grounds",text="Reclaiming Holy Grounds",detail="Vindicator Aluumen wants you to slay 8 Shadowmoon Slayers, 8 Shadowmoon Chosen and 4 Shadowmoon Darkweavers."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=62.6,y=28.4,band={68,70},quest="Tablets of Baa'ri",text="Tablets of Baa'ri",detail="Anchorite Ceyla at the Altar of Sha'tar wants you to collect 12 Baa'ri Tablets from the ground and from Ashtongue Workers at the Ruins of Baa'ri."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=62.6,y=28.4,band={68,70},quest="The Ashtongue Corruptors",text="The Ashtongue Corruptors",detail="Obtain the four medallion fragments from Haalum, Eykenen, Lakaan and Uylaru and return to Anchorite Ceyla at the Altar of Sha'tar in Shadowmoon Valley."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=61.2,y=29.1,band={68,70},quest="The Ashtongue Tribe",text="The Ashtongue Tribe",detail="Vindicator Aluumen wants you to go to the Ruins of Baa'ri and slay 3 Ashtongue Handlers, 4 Ashtongue Warriors and 6 Ashtongue Shaman."},
