{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=65.2,y=44,band={70,70},quest="A Distraction for Akama",text="A Distraction for Akama",detail="Ensure that Akama and Maiev enter the Black Temple in Shadowmoon Valley after Xi'ri's forces create a distraction."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=57.3,y=49.6,band={68,70},quest="Akama",text="Akama",detail="Speak to Akama inside the hidden chamber in the Warden's Cage."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=58.1,y=48.2,band={70,70},quest="Akama's Promise",text="Akama's Promise",detail="Bring the Medallion of Karabor to A'dal in Shattrath City."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=57.3,y=49.6,band={68,70},quest="Proof of Allegiance",text="Proof of Allegiance",detail="Slay Zandras at the Warden's Cage in Shadowmoon Valley and return to Sanoru."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=58.1,y=48.2,band={68,70},quest="The Ata'mal Terrace",text="The Ata'mal Terrace",detail="Go to the top of the Atam'al Terrace in Shadowmoon Valley and obtain the Heart of Fury. Return to Akama at the Warden's Cage in Shadowmoon Valley when you've completed this task."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=55.7,y=58.2,band={68,70},quest="A Necessary Distraction",text="A Necessary Distraction",detail="Larissa Sunstrike wants you to return to the Ruins of Karabor and find a way to unleash Azaloth on his captors."},
{kind="quest",zone="Shadowmoon Valley",mapID=1948,x=59.2,y=58.7,band={70,70},quest="Blood Oath of the Netherwing",text="Blood Oath of the Netherwing"},
