{kind="quest",zone="Isle of Quel'Danas",mapID=1957,x=47.5,y=35.1,band={70,70},quest="The Air Strikes Must Continue",text="The Air Strikes Must Continue",detail="Battlemage Arynna wants you to speak to Ayren Cloudbreaker when you're ready to fly over the Dead Scar. Once there, use the Arcane Charges to kill 2 Pit Overlords, 3 Eredar Sorcerers and 12 Wrath Enforcers."},
{kind="quest",zone="Isle of Quel'Danas",mapID=1957,x=47.7,y=35.1,band={70,70},quest="The Battle Must Go On",text="The Battle Must Go On",detail="Harbinger Inuuro wants you to slay 6 Burning Legion Demons and the Emissary of Hate in Dawning Square. Use the Shattered Sun Banner to impale the Emissary of Hate's corpse."},
