{kind="quest",zone="Isle of Quel'Danas",mapID=1957,x=48.6,y=37.7,band={70,70},quest="Your Continued Support",text="Your Continued Support",detail="Anchorite Ayuri at Sun's Reach in Sunwell Isle wants you to donate 10 gold."},
